sequence.script:
var updatedPayload = mc.getProperty("updatedPayload");

// Convert string → JSON
if (typeof updatedPayload === "string") {
    updatedPayload = JSON.parse(updatedPayload);
}

if (!updatedPayload || !updatedPayload.claimRequest) {
    throw "updatedPayload or claimRequest is missing";
}

var req = updatedPayload.claimRequest;

// Date functions
var currentDate = new Date();

// Format yyyy-MM-dd
function formatDate(date) {
    return date.getFullYear() + "-" +
        ("0" + (date.getMonth() + 1)).slice(-2) + "-" +
        ("0" + date.getDate()).slice(-2);
}

// Generate LossId (yyyyMMddHHSSS)
function generateLossId(date) {
    return date.getFullYear().toString() +
        ("0" + (date.getMonth() + 1)).slice(-2) +
        ("0" + date.getDate()).slice(-2) +
        ("0" + date.getHours()).slice(-2) +
        ("0" + date.getSeconds()).slice(-2) +
        ("00" + date.getMilliseconds()).slice(-3);
}

var ts = formatDate(currentDate);
var LossId = generateLossId(currentDate);

// Extract values 
var policy = req.policy || {};
var insurableObject = (policy.insurableObjects || [])[0] || {};
var coverage = (insurableObject.coverage || [])[0] || {};
var lossItem = (req.lossItems || [])[0] || {};

// Filter POLICY_HOLDER
var reportedBy = "POLICY_HOLDER";
if (req.parties && req.parties.length > 0) {
    for (var i = 0; i < req.parties.length; i++) {
        if (req.parties[i].partyTypeCode === "POLICY_HOLDER") {
            reportedBy = req.parties[i].partyTypeCode;
            break;
        }
    }
}

// Estimated amount
var estimatedLoss = lossItem.estimatedLossAmount || 0;

// Severity logic
var severityCode = "HIGH";
if (estimatedLoss <= 5000) {
    severityCode = "LOW";
} else if (estimatedLoss <= 20000) {
    severityCode = "MODERATE";
}

// Final payload
var result = {
    lossItemIdentifier: "LOSS-" + LossId,
    insurableObjectIdentifier: insurableObject.insurableObjectIdentifier,
    coverageIdentifier: coverage.coverageIdentifier,
    lossTypeCode: lossItem.lossType,
    damageCategory: (req.accidentDetails && req.accidentDetails.cause) || "UNKNOWN",
    description: (req.accidentDetails && req.accidentDetails.description) || req.claimDescription,
    reportedBy: reportedBy,
    incidentDateTime: req.incidentDateTime,
    reportedDateTime: ts,
    estimatedLossAmount: estimatedLoss,
    currencyCode: (coverage.limits && coverage.limits[0] && coverage.limits[0].currencyCode) || "USD",
    severityCode: severityCode,
    lossLocation: "FRONT_LEFT",
    lossStatus: "REPORTED"
};

// Set payload
mc.setPayloadJSON(result);
mc.setProperty("messageType", "application/json");
